insert into wac_birthday_drama_script values (4514061, 4514, 11, '105811', 'これって、誕生日ケーキですか！？\\nありがとうございます♪\\nとってもおいしそう……\\nさっそくパクっといっちゃいますね♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (4514062, 4514, 91, '0', '', '', '', '', '', '', '');
