insert into wac_birthday_drama_script values (4514071, 4514, 11, '105811', 'えへへ、ありがとうございます♪\\nいっぱい味わって食べますね！\\nみんなに祝ってもらえて\\n今日は最高の記念日です♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (4514072, 4514, 91, '0', '', '', '', '', '', '', '');
