insert into wac_birthday_drama_script values (4514075, 4514, 11, '105811', '今日も、明日も、この先の未来も\\n素敵な食卓を囲んでいけますように♪\\nもちろんあなたも一緒ですよ！\\nこれからもよろしくお願いしますね！', '10', '1', '1', '0', '0', '0.5');
