insert into wac_birthday_drama_script values (5214066, 5214, 11, '105511', 'わぁ、お誕生日ケーキですか？\\nおめでとうございます～\\nいったい誰の……えっ、わ、私！？\\n誕生日、覚えててくれたんですか……？', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (5214067, 5214, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (5214068, 5214, 3, '105511', 'wac_birthday_idle_wish', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5214069, 5214, 3, '105311', 'wac_birthday_talk_smile', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5214070, 5214, 21, 'vo_wac_05214', 'vo_wac_05214_001', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (5214071, 5214, 11, '105311', '忘れるはずがないだろう！\\nアユミは我がギルドの数少ない良心……\\nいや、重要な存在なのだからな！\\n盛大に祝福させてくれ！\u3000おめでとう！', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (5214072, 5214, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (5214073, 5214, 3, '105311', 'wac_birthday_idle_doya', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5214074, 5214, 3, '105511', 'wac_birthday_talk_wish', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5214075, 5214, 21, 'vo_wac_05214', 'vo_wac_05214_002', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (5214076, 5214, 11, '105511', 'え、えっと……\\nこれ、夢じゃないですよね？\\nほっぺをつねっても……いひゃい！\\nやっぱり夢じゃないれす！', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (5214077, 5214, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (5214078, 5214, 3, '105511', 'wac_birthday_talk_smile', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5214079, 5214, 21, 'vo_wac_05214', 'vo_wac_05214_003', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (5214080, 5214, 11, '105511', 'うぅっ……あっ、ありがとうございます！\\n先輩にもお祝いしてもらえて\\nとってもうれしいです！\\nえへへ、大切にいただきますね……♪', '10', '1', '1', '0', '0', '0.5');
