insert into wac_birthday_drama_script values (5514055, 5514, 11, '101611', 'わわ、これってうちの誕生日ケーキ？\\nこんなのあるなんて聞いてないし～！\\nオニ感激なんだけど！？', '10', '1', '1', '0', '0', '0.5');
