insert into wac_birthday_drama_script values (5514060, 5514, 11, '105011', 'フフン、感謝しなさいよね～\\nアタシとイオちゃんで徹夜して作っ……いや！\\n大して苦労はしなかったけど！\\nえっと……誕生日おめでと、スズナ。', '10', '1', '1', '0', '0', '0.5');
