insert into wac_birthday_drama_script values (5514065, 5514, 11, '101611', 'あはは、うん、ありがとっ！\\nそれでミサキっちとちゃんイオ\\n朝から甘～い匂いしてたんだね～', '10', '1', '1', '0', '0', '0.5');
