insert into wac_birthday_drama_script values (5514069, 5514, 11, '101611', 'やっぱ持つべきものは\\n友達だし……♪\\nよーし、みんなでパーティーしよー！\\nもちヒデサイも一緒だからね！', '10', '1', '1', '0', '0', '0.5');
