insert into wac_birthday_drama_script values (6214060, 6214, 11, '106611', 'そそそ、そんなことねーですよ！？\\nやろうとしたけどカヤぴぃに\\n止められた……とか\\nそんなことは断じてねーですっ！', '10', '1', '1', '0', '0', '0.5');
