insert into wac_birthday_drama_script values (6214065, 6214, 11, '106731', 'ふふ、ごめんごめん、冗談だよ～\\n……ふふ、ありがとうね。\\nとってもうれしいな♪', '10', '1', '1', '0', '0', '0.5');
